// 话题轮换器 - 7天一轮，每天不同话题
const topics = [
  { day: 0, type: 'joke', topic: '英语笑话', desc: '写一个有趣的英语笑话，让学生在笑声中学单词' },
  { day: 1, type: 'tongue_twister', topic: '英语绕口令', desc: '写一个经典的英语绕口令，训练发音和语感' },
  { day: 2, type: 'tech', topic: 'AI与科技', desc: '介绍最新AI或科技新闻，用初二能懂的英语' },
  { day: 3, type: 'military', topic: '军事前沿', desc: '介绍有趣的军事科技或装备，用简单英语描述' },
  { day: 4, type: 'space', topic: '天文宇宙', desc: '介绍一个天文现象或宇宙知识' },
  { day: 5, type: 'geography', topic: '地理探索', desc: '介绍一个有趣的地方或地理现象' },
  { day: 6, type: 'material', topic: '新材料/物理', desc: '介绍神奇的材料或物理现象' }
];

const today = new Date();
const dayOfWeek = today.getDay();
const selected = topics[dayOfWeek];

return [{
  json: {
    topic_type: selected.type,
    topic_name: selected.topic,
    topic_desc: selected.desc,
    date: today.toISOString().split('T')[0],
    weekday: ['日','一','二','三','四','五','六'][dayOfWeek],
    chatInput: `请为「${selected.topic}」生成今日英语伴学内容。`
  }
}];

// 解析AI输出，组装推送内容
const raw = $input.first().json.output || $input.first().json.message || $input.first().json.text || $input.first().json.content || '';

// 如果AI输出是结构化的，直接使用
// 否则尝试分段解析
let sections = {
  english: '',
  translation: '',
  vocabulary: '',
  patterns: '',
  grammar: '',
  quiz: '',
  encouragement: ''
};

if (raw.includes('---ENGLISH---')) {
  const parts = raw.split('---');
  // 简单分段解析
  sections.english = (raw.match(/---ENGLISH---([\s\S]*?)(?=---|$)/) || ['',''])[1].trim();
  sections.translation = (raw.match(/---TRANSLATION---([\s\S]*?)(?=---|$)/) || ['',''])[1].trim();
  sections.vocabulary = (raw.match(/---VOCABULARY---([\s\S]*?)(?=---|$)/) || ['',''])[1].trim();
  sections.patterns = (raw.match(/---PATTERNS---([\s\S]*?)(?=---|$)/) || ['',''])[1].trim();
  sections.grammar = (raw.match(/---GRAMMAR---([\s\S]*?)(?=---|$)/) || ['',''])[1].trim();
  sections.quiz = (raw.match(/---QUIZ---([\s\S]*?)(?=---|$)/) || ['',''])[1].trim();
  sections.encouragement = (raw.match(/---ENCOURAGEMENT---([\s\S]*?)(?=---|$)/) || ['',''])[1].trim();
} else {
  // 如果没有分段标记，整段输出
  sections.english = raw;
}

const topicInfo = $('话题轮换').first().json;
const today = new Date();
const dateStr = today.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' });

// 组装Markdown格式的推送内容
const markdown = `# 📖 每日英语伴学 | ${dateStr}
## 🎯 今日主题：${topicInfo.topic_name}

---

## 📝 英文原文
${sections.english}

---

## 🌏 中文译文
${sections.translation}

---

## 📚 重点词汇
${sections.vocabulary}

---

## 🔑 重点句型
${sections.patterns}

---

## 📐 语法要点
${sections.grammar}

---

## ✅ 今日小测
${sections.quiz}

---

## 💪 ${sections.encouragement}
`;

return [{
  json: {
    title: `每日英语 | ${topicInfo.topic_name} | ${dateStr}`,
    content: markdown,
    topic: topicInfo.topic_name,
    date: dateStr
  }
}];
